defmodule BlogWeb.PostLive do
  use Phoenix.LiveView

  def mount(_params, _session, socket) do
    {:ok, assign(socket, :post, %{})}
  end

  def handle_event("submit_post", %{"post" => post_params}, socket) do
    sanitized_content = sanitize_html(post_params["content"])
    {:noreply, assign(socket, :post, %{content: sanitized_content})}
  end

  defp sanitize_html(html) do
    Phoenix.HTML.html_escape(html)
  end
end

defmodule BlogWeb.PostLive.Template do
  use Phoenix.LiveView.Template

  def render(assigns) do
    ~L"""
    <form phx-submit="submit_post">
      <textarea name="post[content]" phx-debounce="500"><%= @post.content %></textarea>
      <button type="submit">Submit</button>
    </form>

    <%= raw(@post.content) %>
    """
  end
end